#!/usr/bin/env python3
import sys
P = "nexus-base-frontend.html"
s = open(P, encoding="utf-8").read()
if "Contact Log (" in s:
    print("[SKIP] complete case card already applied."); sys.exit(0)
try:
    start = s.index('det.innerHTML=`<div class="record-card">')
    end = s.index('`;', start) + 2
except ValueError:
    print("[FAIL] record card anchor not found - nothing changed."); sys.exit(1)
NEW = '''det.innerHTML=`<div class="record-card"><div class="record-header"><div class="record-id">&#9672; ${ENTITY.toUpperCase()} RECORD &#8212; #${rec.id}</div>${statusBadge(rec.status)}</div><div class="record-fields">${FIELDS.map((f,i)=>`<div class="record-field"><div class="record-field-label">${fieldLabel(i)}</div><div class="record-field-value">${rec["field_"+(i+1)]||"&#8212;"}</div></div>`).join("")}</div>${rec.notes?`<div style="padding:16px;border-top:1px solid var(--border)"><div class="record-field-label" style="margin-bottom:6px">Notes</div><div style="font-size:13px;color:var(--text2);line-height:1.6">${rec.notes}</div></div>`:""}${d.contacts&&d.contacts.length?`<div style="padding:16px;border-top:1px solid var(--border)"><div class="record-field-label" style="margin-bottom:10px;color:var(--cyan)">&#9742; Contact Log (${d.contacts.length})</div>${d.contacts.map(c=>`<div style="padding:10px 14px;background:var(--bg3);border:1px solid var(--border);border-radius:8px;margin-bottom:8px"><div style="font-size:12px;font-weight:700;color:var(--cyan)">${c.contact_type||"Contact"} <span style="color:var(--text3);font-weight:400">&middot; ${new Date(c.created_at).toLocaleDateString()}${c.author?" &middot; "+c.author:""}</span></div><div style="font-size:13px;color:var(--text2);margin-top:4px;line-height:1.5">${c.notes||""}</div></div>`).join("")}</div>`:""}${d.documents&&d.documents.length?`<div style="padding:16px;border-top:1px solid var(--border)"><div class="record-field-label" style="margin-bottom:10px;color:var(--violet)">&#128203; Documents (${d.documents.length})</div>${d.documents.map(o=>`<div style="padding:10px 14px;background:var(--bg3);border:1px solid var(--border);border-radius:8px;margin-bottom:8px"><div style="font-size:12px;font-weight:700;color:var(--violet)">${o.document_type||"Document"} <span style="color:var(--text3);font-weight:400">&middot; ${o.document_source||""} &middot; ${o.chain_status||""}</span></div></div>`).join("")}</div>`:""}${d.notes&&d.notes.length?`<div style="padding:16px;border-top:1px solid var(--border)"><div class="record-field-label" style="margin-bottom:10px;color:var(--gold)">&#9999; Governed Notes (${d.notes.length})</div>${d.notes.map(n=>`<div style="padding:10px 14px;background:var(--bg3);border:1px solid var(--border);border-radius:8px;margin-bottom:8px"><div style="font-size:12px;font-weight:700;color:var(--gold)">${n.note_type||"note"} <span style="color:var(--text3);font-weight:400">&middot; ${new Date(n.created_at).toLocaleDateString()}</span></div><div style="font-size:13px;color:var(--text2);margin-top:4px;line-height:1.5">${n.content||""}</div></div>`).join("")}</div>`:""}<div style="padding:14px 16px;border-top:1px solid var(--border);display:flex;gap:10px"><button class="btn btn-ghost btn-sm" onclick="document.getElementById('record-detail').style.display='none'">&#10005; Close</button><button class="btn btn-primary btn-sm" onclick="showMode('rawnote')">&#9999; Add Note</button></div></div>`;'''
s = s[:start] + NEW + s[end:]
open(P, "w", encoding="utf-8").write(s)
print("[OK] complete case card: contact log + documents + governed notes now render")
